module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output o_en
);
    parameter PIPELINE_STAGES = 3;
    reg [3:0] reg_i_en;
    reg [64:0] reg_result;
    reg reg_o_en;
    wire [63:0] sum_ripple_64bit_stage;
    wire carry_ripple_64bit_stage;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_i_en <= 4'b0;
            reg_result <= 65'b0;
            reg_o_en <= 1'b0;
        end else begin
            reg_i_en[0] <= i_en;
            reg_result[64:0] <= {adda[63:0], addb[63:0], 1'b0};
            reg_o_en <= reg_i_en[PIPELINE_STAGES];
        end
    end
    genvar i;
    generate
        for (i = 0; i < PIPELINE_STAGES; i = i + 1) begin : pipeline_stages
            wire [63:0] a, b;
            wire carry;
            if (i == 0) begin
                assign a = reg_result[63:0];
                assign b = reg_addb;
                assign carry = reg_i_en[0];
            end else begin
                assign a = reg_result[63:0];
                assign b = sum_ripple_64bit_stage;
                assign carry = carry_ripple_64bit_stage;
            end
            wire [63:0] sum;
            wire carry_out;
            assign {carry_out, sum} = a + b + carry;
            assign sum_ripple_64bit_stage = sum;
            assign carry_ripple_64bit_stage = carry_out;
            always @(posedge clk or negedge rst_n) begin
                if (!rst_n) begin
                    reg_i_en[i+1] <= 1'b0;
                    reg_result <= 65'b0;
                    reg_o_en <= 1'b0;
                end else begin
                    reg_i_en[i+1] <= reg_i_en[i];
                    reg_result <= {sum_ripple_64bit_stage, carry_ripple_64bit_stage, reg_result[63:0]};
                    reg_o_en <= reg_i_en[PIPELINE_STAGES];
                end
            end
        end
    endgenerate
    assign result = reg_result;
    assign o_en = reg_o_en;
endmodule
